import{j as e,b as t,c as o,aa as a}from"./chunks/framework.Bxf40uRC.js";const u=JSON.parse('{"title":"socket编程","description":"","frontmatter":{},"headers":[],"relativePath":"计算机网络/socket.md","filePath":"计算机网络/socket.md","lastUpdated":null}'),c={name:"计算机网络/socket.md"},s=a('<h1 id="socket编程" tabindex="-1">socket编程 <a class="header-anchor" href="#socket编程" aria-label="Permalink to &quot;socket编程&quot;">​</a></h1><p><img src="https://s2.loli.net/2024/03/12/vUOJitXDWVpcdZa.png" alt="socket图解"></p><ul><li>常用的socket类型有两种: 流式socket和数据报式socket，流式是一种面向连接的socket，针对于面向连接的TCP服务应用，数据报式socket是一种无连接的socket，针对于无连接的UDP服务应用；</li></ul><h2 id="socket服务器和客户端工作流程" tabindex="-1">socket服务器和客户端工作流程? <a class="header-anchor" href="#socket服务器和客户端工作流程" aria-label="Permalink to &quot;socket服务器和客户端工作流程?&quot;">​</a></h2><h3 id="服务器端的工作流程" tabindex="-1">服务器端的工作流程 <a class="header-anchor" href="#服务器端的工作流程" aria-label="Permalink to &quot;服务器端的工作流程&quot;">​</a></h3><ol><li>创建socket：服务器端会先创建一个socket，用于监听来自客户端的连接请求；</li><li>bind：服务器端将socket绑定到一个指定的网络地址和端口，从而监听来自于这个地址和端口的请求；</li><li>Listen：监听绑定地址上的请求，等待客户端的连接请求；</li><li>accept：接受连接，当一个客户端请求连接的时候，服务器端的socket接受请求并建立一个新的socket连接，专门用于与该客户端进行通信；</li><li>数据交换：一旦建立连接，服务器端就可以通过新建立的socket与客户端进行数据读写操作；</li><li>关闭连接：数据交换完成后，服务器端关闭与客户端的连接。服务器可以继续监听其他客户端的连接请求；</li></ol><h3 id="客户端的工作流程" tabindex="-1">客户端的工作流程 <a class="header-anchor" href="#客户端的工作流程" aria-label="Permalink to &quot;客户端的工作流程&quot;">​</a></h3><ol><li>创建Socket：客户端创建一个socket，用于与服务器端的socket进行连接；</li><li>connect：客户端的socket尝试连接服务器端的socket，需要指定服务器的网络地址和端口号；</li><li>数据交换；</li><li>关闭连接；</li></ol>',8),l=[s];function i(r,k,n,d,h,_){return t(),o("div",null,l)}const m=e(c,[["render",i]]);export{u as __pageData,m as default};
